from lxml import etree
import io

def process_soap_request(xml_content):
    # Enable DTD validation
    parser = etree.XMLParser(load_dtd=True, no_network=False, remove_blank_text=True)
    
    try:
        # Parse the XML content with DTD validation
        root = etree.fromstring(xml_content.encode('utf-8'), parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Check if it's a valid SOAP envelope
    soap_namespace = "http://schemas.xmlsoap.org/soap/envelope/"
    if root.tag != f"{{{soap_namespace}}}Envelope":
        raise ValueError("Not a valid SOAP envelope")
    
    # Extract the body
    body = root.find(f".//{{{soap_namespace}}}Body")
    if body is None:
        raise ValueError("SOAP body not found")
    
    # Return the body content as string
    return etree.tostring(body, encoding='unicode', pretty_print=True)

def process_soap_request_with_validation(xml_content, dtd_file=None):
    # Create parser with DTD validation
    if dtd_file:
        parser = etree.XMLParser(load_dtd=True, no_network=False, remove_blank_text=True, dtd_validation=True)
        with open(dtd_file, 'r') as f:
            dtd_content = f.read()
        dtd = etree.DTD(dtd_content)
    else:
        parser = etree.XMLParser(load_dtd=True, no_network=False, remove_blank_text=True)
    
    try:
        # Parse the XML content
        root = etree.fromstring(xml_content.encode('utf-8'), parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Validate against DTD if provided
    if dtd_file:
        try:
            root.validate(dtd)
        except Exception as e:
            raise ValueError(f"DTD validation failed: {e}")
    
    # Extract the body
    soap_namespace = "http://schemas.xmlsoap.org/soap/envelope/"
    body = root.find(f".//{{{soap_namespace}}}Body")
    if body is None:
        raise ValueError("SOAP body not found")
    
    # Return the body content as string
    return etree.tostring(body, encoding='unicode', pretty_print=True)